} from '@heroicons/react/24/outline';

const GlassCard = ({ children, className = "" }) => (
  <div className={`backdrop-blur-md bg-white/70 border border-white/20 shadow-sm rounded-2xl ${className}`}>
    {children}
  </div>
);

const MLPredictionTab = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [predictions, setPredictions] = useState(null);
  const [recentAnalysis, setRecentAnalysis] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [overviewRes, recentRes] = await Promise.all([
        fetch('http://localhost:5000/api/ml/prediction/overview'),
        fetch('http://localhost:5000/api/ml/prediction/recent')
      ]);

      const overview = await overviewRes.json();
      const recent = await recentRes.json();

      setPredictions(overview);
      setRecentAnalysis(recent.complaints || []);
    } catch (error) {
      console.error('Error fetching ML data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  const tabs = [
    { id: 'overview', name: 'Intelligence', icon: CpuChipIcon },
    { id: 'analysis', name: 'System Analysis', icon: BeakerIcon },
    { id: 'algorithms', name: 'Model Engine', icon: IdentificationIcon },
    { id: 'forecast', name: 'Forecasts', icon: ArrowTrendingUpIcon },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navigation Bar */}
      <GlassCard className="p-1 px-2 flex space-x-1 bg-gray-50/50">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 flex items-center justify-center py-3 px-4 rounded-xl text-xs font-bold transition-all duration-300 ${activeTab === tab.id
                ? 'bg-white text-purple-600 shadow-sm'
                : 'text-gray-500 hover:text-gray-900 hover:bg-white/50'
              }`}
          >
            <tab.icon className={`h-4 w-4 mr-2 ${activeTab === tab.id ? 'text-purple-600' : 'text-gray-400'}`} />
            {tab.name}
          </button>
        ))}
      </GlassCard>

      {/* Tab Content Rendering */}
      <div className="min-h-[400px]">
        {activeTab === 'overview' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <GlassCard className="p-8">
              <h3 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
                <ChartBarIcon className="h-5 w-5 mr-3 text-blue-600" />
                Live Network Health
              </h3>
              <div className="space-y-6">
                {[
                  { label: 'Total Node Complaints', value: predictions?.currentStats?.total, color: 'text-gray-900' },
                  { label: 'Active Processing', value: predictions?.currentStats?.active, color: 'text-orange-600' },
                  { label: 'System Resolutions', value: predictions?.currentStats?.resolved, color: 'text-green-600' },
                  { label: 'Resolution Efficiency', value: `${predictions?.currentStats?.resolutionRate}%`, color: 'text-purple-600' }
                ].map((stat, i) => (
                  <div key={i} className="flex justify-between items-center pb-4 border-b border-gray-50 last:border-0 last:pb-0">
                    <span className="text-sm font-semibold text-gray-500 uppercase tracking-tight">{stat.label}</span>
                    <span className={`text-lg font-black ${stat.color}`}>{stat.value || 0}</span>
                  </div>
                ))}
              </div>
            </GlassCard>

            <GlassCard className="p-8">
              <h3 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
                <ExclamationTriangleIcon className="h-5 w-5 mr-3 text-red-600" />
                Risk Vector Analysis
              </h3>
              <div className="flex flex-col h-full justify-center -mt-4">
                <div className="flex justify-between items-end mb-4">
                  <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">Global Risk Factor</span>
                  <span className={`text-2xl font-black ${predictions?.predictions?.riskAssessment?.overall === 'high' ? 'text-red-600' : 'text-purple-600'}`}>
                    {predictions?.predictions?.riskAssessment?.overall?.toUpperCase() || 'STABLE'}
                  </span>
                </div>
                <div className="w-full bg-gray-100 rounded-2xl h-4 overflow-hidden shadow-inner">
                  <div
                    className={`h-full rounded-2xl transition-all duration-1000 ${predictions?.predictions?.riskAssessment?.overall === 'high' ? 'bg-red-500' : 'bg-purple-600'
                      }`}
                    style={{ width: `${predictions?.predictions?.riskAssessment?.confidence || 75}%` }}
                  ></div>
                </div>
                <p className="mt-4 text-xs font-bold text-gray-400 uppercase text-center tracking-widest">
                  Intelligence Confidence Score: {predictions?.predictions?.riskAssessment?.confidence || 75}%
                </p>
              </div>
            </GlassCard>
          </div>
        )}

        {activeTab === 'analysis' && (
          <GlassCard className="p-8 overflow-hidden">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-bold text-gray-900">Recent AI Determinations</h3>
              <div className="text-[10px] font-black text-purple-600 uppercase bg-purple-50 px-3 py-1 rounded-full">Automated Audit Log</div>
            </div>
            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {recentAnalysis.map((item, i) => (
                <div key={i} className="flex items-center p-4 bg-white border border-gray-50 rounded-2xl hover:border-purple-200 transition-all hover:shadow-sm">
                  <div className="h-10 w-10 bg-gray-900 rounded-xl flex items-center justify-center mr-4 text-white font-black text-xs">
                    #{item.complaintId.slice(-2)}
                  </div>
                  <div className="flex-1">
                    <div className="text-sm font-bold text-gray-800">{item.title}</div>
                    <div className="flex items-center mt-1 space-x-2">
                      <span className="text-[10px] font-bold text-purple-600 uppercase bg-purple-50 px-2 py-0.5 rounded">
                        {item.mlPredictions?.category?.predicted || item.category}
                      </span>
                      <span className="text-[10px] font-medium text-gray-400 uppercase">
                        Conf: {Math.round((item.mlPredictions?.category?.confidence || 0.8) * 100)}%
                      </span>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-xs font-bold text-gray-900">{new Date(item.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    <div className="text-[10px] font-bold text-gray-400 uppercase">{new Date(item.createdAt).toLocaleDateString()}</div>
                  </div>
                </div>
              ))}
            </div>
          </GlassCard>
        )}

        {activeTab === 'algorithms' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {predictions?.algorithms?.map((algo, index) => (
              <GlassCard key={index} className="p-6 transition-all hover:scale-[1.02]">
                <div className="flex items-center justify-between mb-6">
                  <div className="p-3 bg-gray-900 rounded-2xl">
                    <CpuChipIcon className="h-6 w-6 text-white" />
                  </div>
                  <span className={`px-3 py-1 text-[10px] font-black uppercase rounded-lg ${algo.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                    }`}>
                    {algo.status}
                  </span>
                </div>
                <h3 className="text-lg font-bold text-gray-900 mb-2">{algo.name}</h3>
                <p className="text-xs text-gray-500 font-medium mb-6 line-clamp-2">{algo.description}</p>
                <div className="flex justify-between items-center pt-4 border-t border-gray-50">
                  <span className="text-[10px] font-black text-gray-400 uppercase">Accuracy Rate</span>
                  <span className="text-xl font-black text-gray-900">{algo.accuracy}</span>
                </div>
              </GlassCard>
            ))}
          </div>
        )}

        {activeTab === 'forecast' && (
          <GlassCard className="p-8">
            <h3 className="text-xl font-bold text-gray-900 mb-8 flex items-center">
              <ArrowTrendingUpIcon className="h-5 w-5 mr-3 text-green-600" />
              Temporal Demand Forecast
            </h3>
            <div className="grid grid-cols-7 gap-4">
              {predictions?.predictions?.weeklyForecast?.map((day, index) => (
                <div key={index} className="flex flex-col items-center">
                  <div className="text-[10px] font-black text-gray-400 uppercase mb-4">
                    {new Date(day.date).toLocaleDateString('en', { weekday: 'short' })}
                  </div>
                  <div className="relative w-full flex flex-col items-center">
                    <div className="absolute -top-6 text-sm font-black text-purple-600">{day.predictedComplaints}</div>
                    <div
                      className="w-10 bg-gradient-to-t from-gray-900 to-purple-600 rounded-xl shadow-lg transition-all duration-700"
                      style={{ height: `${(day.predictedComplaints / 50) * 150}px` }}
                    ></div>
                  </div>
                  <div className="mt-4 flex flex-col items-center">
                    <div className="text-[9px] font-black text-gray-400 uppercase mb-1">Confidence</div>
                    <div className="w-8 h-1 bg-gray-100 rounded-full overflow-hidden">
                      <div className="h-full bg-green-500 rounded-full" style={{ width: `${day.confidence}%` }}></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </GlassCard>
        )}
      </div>
    </div>
  );
};

export default MLPredictionTab;
